  const seasonCounts = new Map<string, number>();
  const speedCounts = new Map<string, number>();
  let runFlatCount = 0;
  let snowRatedCount = 0;
  let allWeatherCount = 0;
  let xlCount = 0;
  const loadRangeCounts = new Map<string, number>();

  for (const t of itemsEnriched) {
