          subtitle="Build your lifted truck or SUV setup."
          href="/lifted"
          accent
        />
        <EntryTile
          title="Shop tires"
          subtitle="Search tires by size."
          onClick={() => launch("tires", "size")}
        />
        <EntryTile
          title="Shop wheels"
          subtitle="Search wheels (vehicle-based fitment)."
          onClick={() => launch("wheels", "vehicle")}
        />
      </div>
