import { NextResponse } from "next/server";
import { searchWheels, type WheelSearchParams } from "@/lib/wheelprosProduct";

export const runtime = "nodejs";

/**
 * Wheel search using Wheel Pros Product API
 * This provides real-time inventory and proper vehicle fitment
 */
export async function GET(req: Request) {
  const url = new URL(req.url);
  const t0 = Date.now();

  try {
    const params: WheelSearchParams = {};

    // Vehicle params
    const year = url.searchParams.get("year");
    if (year) params.vehicleYear = parseInt(year, 10);

    const make = url.searchParams.get("make");
    if (make) params.vehicleMake = make;

    const model = url.searchParams.get("model");
    if (model) params.vehicleModel = model;

    const subModel = url.searchParams.get("subModel") || url.searchParams.get("trim");
    if (subModel) params.vehicleSubModel = subModel;

    // Spec filters
    const boltPattern = url.searchParams.get("boltPattern");
    if (boltPattern) params.boltPattern = boltPattern;

    const diameter = url.searchParams.get("diameter");
    if (diameter) params.diameter = parseFloat(diameter);

    const width = url.searchParams.get("width");
    if (width) params.width = width;

    const offsetMin = url.searchParams.get("offsetMin");
    if (offsetMin) params.minOffset = parseFloat(offsetMin);

    const offsetMax = url.searchParams.get("offsetMax");
    if (offsetMax) params.maxOffset = parseFloat(offsetMax);

    const centerbore = url.searchParams.get("centerbore");
    if (centerbore) params.centerbore = centerbore;

    // Other filters
    const brand = url.searchParams.get("brand");
    if (brand) params.brand = brand;

    const finish = url.searchParams.get("finish");
    if (finish) params.finish = finish;

    // Options
    const includeLifted = url.searchParams.get("includeLifted");
    if (includeLifted === "true") params.includeLifted = true;

    // Pagination
    const page = url.searchParams.get("page");
    params.page = page ? Math.max(1, parseInt(page, 10)) : 1;

    const pageSize = url.searchParams.get("pageSize");
    params.pageSize = pageSize ? Math.min(100, Math.max(1, parseInt(pageSize, 10))) : 24;

    // Sorting
    const sortField = url.searchParams.get("sortField") as WheelSearchParams["sortField"];
    if (sortField) params.sortField = sortField;

    const sortOrder = url.searchParams.get("sortOrder") as WheelSearchParams["sortOrder"];
    if (sortOrder) params.sortOrder = sortOrder;

    const result = await searchWheels(params);
    const totalMs = Date.now() - t0;

    // Transform to match our existing frontend format
    const styles = (result.content || []).map(w => ({
      styleKey: w.styleNumber || w.sku || "",
      brand: w.brand || "",
      brandCode: w.brandCode || "",
      model: w.styleName || "",
      imageUrl: w.images?.[0]?.url,
      price: w.msrp || w.mapPrice,
      finishes: [{
        finish: w.finish || "",
        sku: w.sku || "",
        imageUrl: w.images?.[0]?.url,
        price: w.msrp,
        diameter: w.diameter ? String(w.diameter) : undefined,
        width: w.width ? String(w.width) : undefined,
        offset: w.offset ? String(w.offset) : undefined,
      }],
      skus: [{
        sku: w.sku || "",
        diameter: w.diameter ? String(w.diameter) : "",
        width: w.width ? String(w.width) : "",
        offset: w.offset ? String(w.offset) : "",
        boltPattern: w.boltPattern || "",
        centerbore: w.centerbore ? String(w.centerbore) : "",
        finish: w.finish || "",
        price: w.msrp,
      }],
    }));

    // Transform facets
    const facets = {
      brands: (result.facets?.brands || []).map(f => ({
        code: f.key,
        name: f.key,
        count: f.count,
      })),
      finishes: (result.facets?.finishes || []).map(f => ({
        value: f.key,
        count: f.count,
      })),
      diameters: (result.facets?.diameters || []).map(f => ({
        value: String(f.key),
        count: f.count,
      })),
      widths: (result.facets?.widths || []).map(f => ({
        value: String(f.key),
        count: f.count,
      })),
      boltPatterns: (result.facets?.boltPatterns || []).map(f => ({
        value: f.key,
        count: f.count,
      })),
    };

    return NextResponse.json({
      styles,
      totalStyles: result.totalElements || styles.length,
      page: result.pageable?.pageNumber || params.page,
      pageSize: result.pageable?.pageSize || params.pageSize,
      totalPages: result.totalPages || Math.ceil((result.totalElements || 0) / (params.pageSize || 24)),
      facets,
      source: "wheelpros-api",
      timing: { totalMs },
    });

  } catch (err: any) {
    console.error("[wheels/search] WheelPros API error:", err);
    return NextResponse.json(
      { 
        error: "Wheel search failed", 
        message: err?.message || String(err),
        source: "wheelpros-api",
      },
      { status: 502 }
    );
  }
}

/**
 * Wheel Pros Product API client
 * Docs: https://developer.wheelpros.com/assets/specs/product-api/openapi/api.html
 */

import { getWheelProsToken } from "@/lib/wheelprosAuth";

function baseUrl() {
  return process.env.WHEELPROS_PRODUCT_API_BASE_URL || "https://api.wheelpros.com/product/v1";
}

export type WheelSearchParams = {
  // Vehicle fitment
  vehicleYear?: number;
  vehicleMake?: string;
  vehicleModel?: string;
  vehicleSubModel?: string;

  // Specs
  boltPattern?: string;
  diameter?: number;
  width?: string;
  minOffset?: number;
  maxOffset?: number;
  centerbore?: string;

  // Filters
  brand?: string;
  finish?: string;

  // Options
  includeLifted?: boolean;
  includeStaggered?: boolean;
  availabilityType?: "ALL" | "LOCAL" | "AVAILABLE";

  // Pagination
  page?: number;
  pageSize?: number;

  // Sorting
  sortField?: "brand" | "popularity" | "price" | "status" | "style" | "styleNumber";
  sortOrder?: "asc" | "desc";

  // Extra fields
  fields?: string; // e.g., "inventory,price"
};

export type WheelSearchResult = {
  content: Array<{
    sku?: string;
    styleNumber?: string;
    styleName?: string;
    brand?: string;
    brandCode?: string;
    finish?: string;
    diameter?: number;
    width?: number;
    offset?: number;
    boltPattern?: string;
    centerbore?: number;
    msrp?: number;
    mapPrice?: number;
    images?: Array<{ url?: string; type?: string }>;
    inventory?: Array<{ warehouse?: string; quantity?: number }>;
  }>;
  pageable?: {
    pageNumber?: number;
    pageSize?: number;
  };
  totalElements?: number;
  totalPages?: number;
  facets?: {
    brands?: Array<{ key: string; count: number }>;
    finishes?: Array<{ key: string; count: number }>;
    diameters?: Array<{ key: number; count: number }>;
    widths?: Array<{ key: number; count: number }>;
    boltPatterns?: Array<{ key: string; count: number }>;
  };
};

export async function searchWheels(params: WheelSearchParams): Promise<WheelSearchResult> {
  const token = await getWheelProsToken();
  const url = new URL("/wheel/search", baseUrl());

  // Add query params
  if (params.vehicleYear) url.searchParams.set("vehicleYear", String(params.vehicleYear));
  if (params.vehicleMake) url.searchParams.set("vehicleMake", params.vehicleMake);
  if (params.vehicleModel) url.searchParams.set("vehicleModel", params.vehicleModel);
  if (params.vehicleSubModel) url.searchParams.set("vehicleSubModel", params.vehicleSubModel);

  if (params.boltPattern) url.searchParams.set("boltPattern", params.boltPattern);
  if (params.diameter) url.searchParams.set("diameter", String(params.diameter));
  if (params.width) url.searchParams.set("width", params.width);
  if (params.minOffset !== undefined) url.searchParams.set("minOffset", String(params.minOffset));
  if (params.maxOffset !== undefined) url.searchParams.set("maxOffset", String(params.maxOffset));
  if (params.centerbore) url.searchParams.set("centerbore", params.centerbore);

  if (params.brand) url.searchParams.set("brand", params.brand);
  if (params.finish) url.searchParams.set("finish", params.finish);

  if (params.includeLifted) url.searchParams.set("includeLifted", "true");
  if (params.includeStaggered) url.searchParams.set("includeStaggered", "true");
  if (params.availabilityType) url.searchParams.set("availabilityType", params.availabilityType);

  url.searchParams.set("page", String(params.page || 1));
  url.searchParams.set("pageSize", String(params.pageSize || 50));

  if (params.sortField) url.searchParams.set("sortField", params.sortField);
  if (params.sortOrder) url.searchParams.set("sortOrder", params.sortOrder);

  // Always request price info
  url.searchParams.set("fields", params.fields || "price");
  url.searchParams.set("facetCount", "50"); // Get more facet buckets

  const res = await fetch(url.toString(), {
    headers: {
      Accept: "application/json",
      Authorization: `Bearer ${token}`,
    },
    cache: "no-store",
  });

  if (!res.ok) {
    let detail = "";
    try {
      detail = (await res.text()).slice(0, 500);
    } catch {}
    throw new Error(`WheelPros wheel search failed: HTTP ${res.status}${detail ? ` :: ${detail}` : ""}`);
  }

  return (await res.json()) as WheelSearchResult;
}

