"use client";

import { createContext, useContext, useEffect, useState, useCallback, type ReactNode } from "react";
import type { CartAccessoryItem, AccessoryRecommendationState } from "./accessoryTypes";

export type { CartAccessoryItem, AccessoryRecommendationState };

export type CartWheelItem = {
  type: "wheel";
  sku: string;
  rearSku?: string; // For staggered setups
  brand: string;
  model: string;
  finish?: string;
  diameter?: string;
  width?: string;
  rearWidth?: string;
  offset?: string;
  rearOffset?: string;
  boltPattern?: string;
  imageUrl?: string;
  unitPrice: number;
  quantity: number;
  fitmentClass?: "surefit" | "specfit" | "extended";
  vehicle?: {
    year: string;
    make: string;
    model: string;
    trim?: string;
    modification?: string;
  };
  staggered?: boolean;
};

export type CartTireItem = {
  type: "tire";
  sku: string;
  rearSku?: string;
  brand: string;
  model: string;
  size: string;
  rearSize?: string;
  loadIndex?: string;
  speedRating?: string;
  imageUrl?: string;
  unitPrice: number;
  quantity: number;
  vehicle?: {
    year: string;
    make: string;
    model: string;
    trim?: string;
    modification?: string;
  };
  staggered?: boolean;
};

export type CartItem = CartWheelItem | CartTireItem | CartAccessoryItem;

type CartContextValue = {
  items: CartItem[];
  addItem: (item: CartItem) => void;
  addAccessory: (item: CartAccessoryItem) => void;
  addAccessories: (items: CartAccessoryItem[]) => void;
  /** Update an accessory in-place by SKU (safe immutable update). */
  updateAccessory: (sku: string, patch: Partial<CartAccessoryItem>) => void;
  /** Replace an accessory's SKU (e.g., placeholder → real Gorilla SKU). */
  replaceAccessorySku: (oldSku: string, next: CartAccessoryItem) => void;
  removeItem: (sku: string, type: "wheel" | "tire" | "accessory") => void;
  updateQuantity: (sku: string, type: "wheel" | "tire" | "accessory", quantity: number) => void;
  clearCart: () => void;
  getItemCount: () => number;
  getTotal: () => number;
  hasWheels: () => boolean;
  hasTires: () => boolean;
  hasAccessories: () => boolean;
  getWheels: () => CartWheelItem[];
  getTires: () => CartTireItem[];
  getAccessories: () => CartAccessoryItem[];
  getRequiredAccessories: () => CartAccessoryItem[];
  // Accessory recommendation state (for UI)
  accessoryState: AccessoryRecommendationState | null;
  setAccessoryState: (state: AccessoryRecommendationState | null) => void;
  isOpen: boolean;
  setIsOpen: (open: boolean) => void;
  lastAddedItem: CartItem | null;
};

const CartContext = createContext<CartContextValue | null>(null);

const CART_STORAGE_KEY = "wt_cart";

export function CartProvider({ children }: { children: ReactNode }) {
  const [items, setItems] = useState<CartItem[]>([]);
  const [isOpen, setIsOpen] = useState(false);
  const [lastAddedItem, setLastAddedItem] = useState<CartItem | null>(null);
  const [hydrated, setHydrated] = useState(false);
  const [accessoryState, setAccessoryState] = useState<AccessoryRecommendationState | null>(null);

  // Load cart from localStorage on mount
  useEffect(() => {
    try {
      const stored = localStorage.getItem(CART_STORAGE_KEY);
      if (stored) {
        const parsed = JSON.parse(stored);
        if (Array.isArray(parsed)) {
          setItems(parsed);
        }
      }
    } catch {
      // Ignore parse errors
    }
    setHydrated(true);
  }, []);

  // Save cart to localStorage whenever it changes
  useEffect(() => {
    if (hydrated) {
      try {
        localStorage.setItem(CART_STORAGE_KEY, JSON.stringify(items));
      } catch {
        // Ignore storage errors
      }
    }
  }, [items, hydrated]);

  const addItem = useCallback((item: CartItem) => {
    setItems((prev) => {
      // Check if item already exists (same SKU and type)
      const existingIndex = prev.findIndex(
        (i) => i.sku === item.sku && i.type === item.type
      );

      if (existingIndex >= 0) {
        // Update quantity of existing item
        const updated = [...prev];
        updated[existingIndex] = {
          ...updated[existingIndex],
          quantity: updated[existingIndex].quantity + item.quantity,
        };
        return updated;
      }

      // Add new item
      return [...prev, item];
    });
    setLastAddedItem(item);
    setIsOpen(true);
  }, []);

  const removeItem = useCallback((sku: string, type: "wheel" | "tire" | "accessory") => {
    setItems((prev) => prev.filter((i) => !(i.sku === sku && i.type === type)));
  }, []);

  const updateQuantity = useCallback(
    (sku: string, type: "wheel" | "tire" | "accessory", quantity: number) => {
      if (quantity <= 0) {
        removeItem(sku, type);
        return;
      }
      setItems((prev) =>
        prev.map((i) =>
          i.sku === sku && i.type === type ? { ...i, quantity } : i
        )
      );
    },
    [removeItem]
  );

  const clearCart = useCallback(() => {
    setItems([]);
    setLastAddedItem(null);
  }, []);

  const getItemCount = useCallback(() => {
    return items.reduce((sum, i) => sum + i.quantity, 0);
  }, [items]);

  const getTotal = useCallback(() => {
    return items.reduce((sum, i) => sum + i.unitPrice * i.quantity, 0);
  }, [items]);

  const hasWheels = useCallback(() => {
    return items.some((i) => i.type === "wheel");
  }, [items]);

  const hasTires = useCallback(() => {
    return items.some((i) => i.type === "tire");
  }, [items]);

  const getWheels = useCallback(() => {
    return items.filter((i): i is CartWheelItem => i.type === "wheel");
  }, [items]);

  const getTires = useCallback(() => {
    return items.filter((i): i is CartTireItem => i.type === "tire");
  }, [items]);

  const hasAccessories = useCallback(() => {
    return items.some((i) => i.type === "accessory");
  }, [items]);

  const getAccessories = useCallback(() => {
    return items.filter((i): i is CartAccessoryItem => i.type === "accessory");
  }, [items]);

  const getRequiredAccessories = useCallback(() => {
    return items.filter(
      (i): i is CartAccessoryItem => i.type === "accessory" && i.required
    );
  }, [items]);

  const addAccessory = useCallback((item: CartAccessoryItem) => {
    setItems((prev) => {
      // Check if already exists
      const existingIndex = prev.findIndex(
        (i) => i.type === "accessory" && i.sku === item.sku
      );
      if (existingIndex >= 0) {
        // Already added, don't duplicate
        return prev;
      }
      console.log("[cart] Adding accessory:", item.sku, item.name);
      return [...prev, item];
    });
  }, []);

  const addAccessories = useCallback((newItems: CartAccessoryItem[]) => {
    setItems((prev) => {
      const existingSkus = new Set(
        prev.filter((i) => i.type === "accessory").map((i) => i.sku)
      );
      const toAdd = newItems.filter((i) => !existingSkus.has(i.sku));
      if (toAdd.length === 0) return prev;
      console.log("[cart] Adding accessories:", toAdd.map((i) => i.sku));
      return [...prev, ...toAdd];
    });
  }, []);

  const updateAccessory = useCallback((sku: string, patch: Partial<CartAccessoryItem>) => {
    setItems((prev) =>
      prev.map((i) => {
        if (i.type !== "accessory") return i;
        if (i.sku !== sku) return i;
        return { ...(i as CartAccessoryItem), ...patch };
      })
    );
  }, []);

  const replaceAccessorySku = useCallback((oldSku: string, next: CartAccessoryItem) => {
    setItems((prev) => {
      const withoutOld = prev.filter((i) => !(i.type === "accessory" && i.sku === oldSku));
      // If new sku already exists, don't duplicate; instead merge meta onto existing.
      const existingIdx = withoutOld.findIndex((i) => i.type === "accessory" && i.sku === next.sku);
      if (existingIdx >= 0) {
        const updated = [...withoutOld];
        const existing = updated[existingIdx] as CartAccessoryItem;
        updated[existingIdx] = {
          ...existing,
          ...next,
          meta: { ...(existing.meta || {}), ...(next.meta || {}) },
        };
        return updated;
      }
      return [...withoutOld, next];
    });
  }, []);

  return (
    <CartContext.Provider
      value={{
        items,
        addItem,
        addAccessory,
        addAccessories,
        updateAccessory,
        replaceAccessorySku,
        removeItem,
        updateQuantity,
        clearCart,
        getItemCount,
        getTotal,
        hasWheels,
        hasTires,
        hasAccessories,
        getWheels,
        getTires,
        getAccessories,
        getRequiredAccessories,
        accessoryState,
        setAccessoryState,
        isOpen,
        setIsOpen,
        lastAddedItem,
      }}
    >
      {children}
    </CartContext.Provider>
  );
}

export function useCart() {
  const ctx = useContext(CartContext);
  if (!ctx) {
    throw new Error("useCart must be used within a CartProvider");
  }
  return ctx;
}

import Link from "next/link";
import { GarageWidget } from "@/components/GarageWidget";
import { RecommendedFitmentCard } from "@/components/RecommendedFitmentCard";
import { BRAND } from "@/lib/brand";
import { AutoSubmitSelect } from "@/components/AutoSubmitSelect";
import { FavoritesButton } from "@/components/FavoritesButton";
import { vehicleSlug } from "@/lib/vehicleSlug";
import { SelectTireButton } from "@/components/SelectTireButton";
import { SelectTireButtonAxle } from "@/components/SelectTireButtonAxle";
import { TireMatchingBanner } from "@/components/TireMatchingBanner";
import { QuickAddTireButton } from "@/components/AddTiresToCartButton";
import { PackageSummary } from "@/components/PackageSummary";
import {
  generatePlusSizeCandidates,
  type PlusSizeCandidate,
} from "@/lib/tirePlusSizing";
import { getDisplayTrim } from "@/lib/vehicleDisplay";

type Tire = {
  source?: "wp" | "km";
  partNumber?: string;
  mfgPartNumber?: string;
  brand?: string;
  description?: string;
  cost?: number;
  quantity?: { primary?: number; alternate?: number; national?: number };
  imageUrl?: string;
  displayName?: string;
  badges?: {
    terrain?: string | null;
    construction?: string | null;
    warrantyMiles?: number | null;
    loadIndex?: string | null;
    speedRating?: string | null;
  };
  prettyName?: string;
};

type TireAsset = {
  km_description?: string;
  display_name?: string;
  image_url?: string;
};

// Premium tire brands for scoring
const PREMIUM_BRANDS = ["michelin", "bridgestone", "continental", "goodyear", "pirelli"];
const MID_TIER_BRANDS = ["cooper", "toyo", "bfgoodrich", "yokohama", "hankook", "falken", "general", "kumho", "nexen"];

function getBaseUrl() {
  if (process.env.NEXT_PUBLIC_BASE_URL) return process.env.NEXT_PUBLIC_BASE_URL;
  if (process.env.VERCEL_URL) return `https://${process.env.VERCEL_URL}`;
  return "http://localhost:3000";
}

async function fetchFitment(params: Record<string, string | undefined>) {
  const sp = new URLSearchParams();
  for (const [k, v] of Object.entries(params)) {
    if (v) sp.set(k, v);
  }
  const res = await fetch(`${getBaseUrl()}/api/vehicles/tire-sizes?${sp.toString()}`, { cache: "no-store" });
  if (!res.ok) return { error: await res.text() };
  return res.json();
}

// DB-first fitment profile fetch (primary source of truth when available)
async function fetchDBProfile(params: Record<string, string | undefined>) {
  const sp = new URLSearchParams();
  for (const [k, v] of Object.entries(params)) {
    if (v) sp.set(k, v);
  }
  // Use fitment-search which returns dbProfile
  const res = await fetch(`${getBaseUrl()}/api/wheels/fitment-search?${sp.toString()}&pageSize=1`, { cache: "no-store" });
  if (!res.ok) return null;
  const data = await res.json();
  return data?.fitment?.dbProfile || null;
}

async function fetchKmTires(tireSize: string) {
  const sizeQ = normalizeTireSizeForQuery(tireSize);
  const res = await fetch(`${getBaseUrl()}/api/km/tiresizesearch?tireSize=${encodeURIComponent(sizeQ)}&minQty=4`, {
    cache: "no-store",
  });
  if (!res.ok) return { error: await res.text() };
  return res.json();
}

function normalizeTireSizeForQuery(s: string) {
  const v = String(s || "").trim().toUpperCase();
  const m = v.match(/\b(\d{3}\/\d{2})(?:ZR|R)(\d{2})\b/);
  if (m) return `${m[1]}R${m[2]}`;
  return String(s || "").trim();
}

async function fetchWpTires(tireSize: string) {
  const sizeQ = normalizeTireSizeForQuery(tireSize);
  const res = await fetch(`${getBaseUrl()}/api/wp/tires/search?size=${encodeURIComponent(sizeQ)}&minQty=4`, {
    cache: "no-store",
  });
  if (!res.ok) return { error: await res.text() };
  return res.json();
}

async function fetchActiveRebates() {
  const res = await fetch(`${getBaseUrl()}/api/rebates/active`, { cache: "no-store" });
  if (!res.ok) return { items: [] as any[] };
  return res.json();
}

// Score tires for "Top Picks" selection
function scoreTireForPicks(tire: Tire): number {
  let score = 0;
  const price = typeof tire.cost === "number" ? tire.cost + 50 : 0;
  const brand = String(tire.brand || "").toLowerCase();

  // Price sweet spot ($80-$200 per tire)
  if (price >= 80 && price <= 200) score += 30;
  else if (price >= 60 && price <= 250) score += 15;
